@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_element">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _element;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("initialize", _element, _dotNetRef, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task NotifyIdle()
    {
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task NotifyActive()
    {
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose");
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

let state = null;

export function initialize(element, dotNetRef, timeoutMs) {
    const events = ["mousemove", "keydown", "click", "scroll"];
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }

        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("NotifyActive");
        }

        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("NotifyIdle");
        }, timeoutMs);
    }

    events.forEach(evt => element.addEventListener(evt, resetTimer, { passive: true }));

    // Start the initial timer
    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("NotifyIdle");
    }, timeoutMs);

    state = { element, events, resetTimer, timerId: () => timerId, clearTimer: () => clearTimeout(timerId) };
}

export function dispose() {
    if (state) {
        state.clearTimer();
        state.events.forEach(evt => state.element.removeEventListener(evt, state.resetTimer));
        state = null;
    }
}

